  1→<div class="max-w-6xl mx-auto px-4 py-8">
  2→  <h1 class="text-2xl font-bold text-gray-900 mb-6">Docker</h1>
  3→
  4→  <%# ── Docker daemon info ── %>
  5→  <div class="bg-white border border-gray-200 rounded-lg p-4 mb-6">
  6→    <% begin %>
  7→      <% info = Docker.info %>
  8→      <% version = Docker.version %>
  9→      <div class="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm">
 10→        <div>
 11→          <span class="text-gray-500 block">Version</span>
 12→          <span class="font-mono font-medium"><%= version["Version"] %></span>
 13→        </div>
 14→        <div>
 15→          <span class="text-gray-500 block">API Version</span>
 16→          <span class="font-mono font-medium"><%= version["ApiVersion"] %></span>
 17→        </div>
 18→        <div>
 19→          <span class="text-gray-500 block">Containers</span>
 20→          <span class="font-mono font-medium"><%= info["ContainersRunning"] %> running / <%= info["Containers"] %> total</span>
 21→        </div>
 22→        <div>
 23→          <span class="text-gray-500 block">Images</span>
 24→          <span class="font-mono font-medium"><%= info["Images"] %></span>
 25→        </div>
 26→        <div>
 27→          <span class="text-gray-500 block">Storage Driver</span>
 28→          <span class="font-mono font-medium"><%= info["Driver"] %></span>
 29→        </div>
 30→        <div>
 31→          <span class="text-gray-500 block">Runtimes</span>
 32→          <span class="font-mono font-medium"><%= info["Runtimes"]&.keys&.join(", ") %></span>
 33→        </div>
 34→        <div>
 35→          <span class="text-gray-500 block">OS / Arch</span>
 36→          <span class="font-mono font-medium"><%= info["OperatingSystem"] %> (<%= info["Architecture"] %>)</span>
 37→        </div>
 38→        <div>
 39→          <span class="text-gray-500 block">Docker Root</span>
 40→          <span class="font-mono font-medium"><%= info["DockerRootDir"] %></span>
 41→        </div>
 42→      </div>
 43→    <% rescue Docker::Error::DockerError => e %>
 44→      <p class="text-red-600 text-sm">Failed to connect to Docker: <%= e.message %></p>
 45→    <% end %>
 46→  </div>
 47→
 48→  <%# ── Service tabs ── %>
 49→  <div class="bg-white border border-gray-200 rounded-lg overflow-hidden">
 50→    <div class="border-b border-gray-200 flex" id="service-tabs">
 51→      <% @containers.each_with_index do |c, i| %>
 52→        <button type="button"
 53→                data-container="<%= c[:name] %>"
 54→                onclick="selectTab(this)"
 55→                class="service-tab relative px-5 py-3 text-sm font-medium transition-colors
 56→                       <%= i == 0 ? 'text-blue-600 border-b-2 border-blue-600' : 'text-gray-500 hover:text-gray-700' %>">
 57→          <span class="inline-block w-2 h-2 rounded-full mr-1.5 <%= c[:exists] && c[:state] == 'running' ? 'bg-green-500' : 'bg-red-500' %>"></span>
 58→          <%= c[:name].delete_prefix("sandcastle-").delete_suffix("-1") %>
 59→          <% if c[:exists] %>
 60→            <span class="ml-1 text-xs text-gray-400 font-normal"><%= c[:status] %></span>
 61→          <% end %>
 62→        </button>
 63→      <% end %>
 64→    </div>
 65→
 66→    <%# ── Log panel (shared, full width) ── %>
 67→    <div class="p-4">
 68→      <div class="flex items-center justify-between mb-3">
 69→        <div class="flex items-center gap-3">
 70→          <span class="text-sm text-gray-500">Showing last <span id="log-line-count">200</span> lines</span>
 71→          <label class="inline-flex items-center gap-1.5 text-sm text-gray-600 cursor-pointer">
 72→            <input type="checkbox" id="auto-tail" checked
 73→                   class="rounded border-gray-300 text-blue-600 focus:ring-blue-500"
 74→                   onchange="toggleAutoTail()">
 75→            Auto-tail
 76→          </label>
 77→        </div>
 78→        <div class="flex items-center gap-2">
 79→          <select id="tail-select" onchange="reloadCurrentLogs()"
 80→                  class="text-xs border border-gray-300 rounded px-2 py-1 bg-white">
 81→            <option value="100">100 lines</option>
 82→            <option value="200" selected>200 lines</option>
 83→            <option value="500">500 lines</option>
 84→            <option value="1000">1000 lines</option>
 85→          </select>
 86→          <button type="button" onclick="reloadCurrentLogs()"
 87→                  class="text-xs px-2 py-1 bg-gray-100 text-gray-600 rounded hover:bg-gray-200">
 88→            Refresh
 89→          </button>
 90→        </div>
 91→      </div>
 92→      <pre id="log-output" class="bg-gray-900 text-gray-100 text-xs rounded p-4 overflow-x-auto overflow-y-auto font-mono whitespace-pre-wrap" style="height: 28rem;"></pre>
 93→    </div>
 94→  </div>
 95→</div>
 96→
 97→<script>
 98→  var currentContainer = "<%= @containers.first&.dig(:name) %>";
 99→  var tailInterval = null;
100→
101→  function selectTab(button) {
102→    // Update tab styles
103→    document.querySelectorAll(".service-tab").forEach(function(tab) {
104→      tab.classList.remove("text-blue-600", "border-b-2", "border-blue-600");
105→      tab.classList.add("text-gray-500");
106→    });
107→    button.classList.remove("text-gray-500");
108→    button.classList.add("text-blue-600", "border-b-2", "border-blue-600");
109→
110→    currentContainer = button.dataset.container;
111→    loadLogs(currentContainer);
112→  }
113→
114→  function reloadCurrentLogs() {
115→    loadLogs(currentContainer);
116→  }
117→
118→  function loadLogs(name) {
119→    var tail = document.getElementById("tail-select").value;
120→    var output = document.getElementById("log-output");
121→    var countSpan = document.getElementById("log-line-count");
122→    countSpan.textContent = tail;
123→
124→    fetch("/admin/docker/" + encodeURIComponent(name) + "/logs?tail=" + tail, {
125→      headers: { "Accept": "application/json" }
126→    })
127→      .then(function(r) { return r.json(); })
128→      .then(function(data) {
129→        if (data.error) {
130→          output.textContent = "Error: " + data.error;
131→        } else {
132→          output.textContent = data.lines.join("\n");
133→          output.scrollTop = output.scrollHeight;
134→        }
135→      })
136→      .catch(function(e) {
137→        output.textContent = "Failed to fetch logs: " + e.message;
138→      });
139→  }
140→
141→  function toggleAutoTail() {
142→    if (document.getElementById("auto-tail").checked) {
143→      startAutoTail();
144→    } else {
145→      stopAutoTail();
146→    }
147→  }
148→
149→  function startAutoTail() {
150→    stopAutoTail();
151→    tailInterval = setInterval(function() {
152→      loadLogs(currentContainer);
153→    }, 3000);
154→  }
155→
156→  function stopAutoTail() {
157→    if (tailInterval) {
158→      clearInterval(tailInterval);
159→      tailInterval = null;
160→    }
161→  }
162→
163→  // Load first tab on page load and start auto-tail
164→  if (currentContainer) {
165→    loadLogs(currentContainer);
166→    startAutoTail();
167→  }
168→
169→  // Stop polling when leaving the page
170→  document.addEventListener("turbo:before-cache", stopAutoTail);
171→  document.addEventListener("turbo:before-visit", stopAutoTail);
172→</script>
